  id: string;
  date: string;
  description: string;
  type: TransactionType;
  amount: number;
  currencyValue: number;
  icon: string;
  details: {
    provider: string;
    extraInfo: string;
    fields: Array<{
      label: string;
      value: string;
    }>;
  };
  status: string
}

